import React, { useEffect, useRef } from 'react';
import { useStaticQuery, graphql, Link } from 'gatsby';
import styled from 'styled-components';
import sr from '@utils/sr';
import { srConfig } from '@config';
import { usePrefersReducedMotion } from '@hooks';

const StyledProjectsGrid = styled.ul`
  ${({ theme }) => theme.mixins.resetList};
  display: grid;
  gap: 0;
`;

const StyledProject = styled.li`
  padding: 28px 0;
  border-top: 1px solid var(--lightest-navy);

  &:first-of-type {
    border-top: 0;
    padding-top: 0;
  }

  @media (prefers-reduced-motion: no-preference) {
    transition: background-color 180ms ease, transform 180ms ease;
  }

  &:hover,
  &:focus-within {
    background-color: rgba(255, 255, 255, 0.58);
    transform: translateX(4px);
  }

  .project-row {
    display: flex;
    align-items: flex-start;
    justify-content: space-between;
    gap: 28px;

    @media (max-width: 768px) {
      display: block;
    }
  }

  .project-meta {
    flex: 0 0 132px;
    color: var(--green);
    font-family: var(--font-ui);
    font-size: var(--fz-xs);
    font-weight: 600;
    letter-spacing: 0.08em;
    text-transform: uppercase;

    @media (max-width: 768px) {
      margin-bottom: 10px;
    }
  }

  .project-body {
    flex: 1 1 auto;
    min-width: 0;
  }

  .project-title {
    margin: 0;
    color: var(--lightest-slate);
    font-size: clamp(22px, 2.4vw, 28px);
    line-height: 1.2;

    a {
      color: inherit;

      &:hover,
      &:focus-visible {
        color: var(--green);
      }
    }
  }

  .project-description {
    margin-top: 12px;
    color: var(--slate);
    font-size: var(--fz-sm);
    line-height: 1.7;
    max-width: 64ch;

    a {
      ${({ theme }) => theme.mixins.inlineLink};
    }

    strong {
      color: var(--lightest-slate);
      font-weight: 600;
    }

    p:last-child {
      margin-bottom: 0;
    }
  }

  .project-tech-list {
    display: flex;
    flex-wrap: wrap;
    margin: 16px 0 0;
    padding: 0;
    list-style: none;

    li {
      margin: 0 14px 8px 0;
      color: var(--light-slate);
      font-family: var(--font-mono);
      font-size: var(--fz-xs);
      white-space: nowrap;
      line-height: 1.5;
    }
  }

  .project-links {
    display: flex;
    align-items: center;
    flex-wrap: wrap;
    gap: 10px;
    margin-top: 18px;

    a {
      display: inline-flex;
      align-items: center;
      justify-content: center;
      width: max-content;
      color: var(--green);
      font-family: var(--font-ui);
      font-size: var(--fz-sm);
      font-weight: 600;
      line-height: 1.2;
      text-decoration: none;
      transition: color 180ms ease, transform 180ms ease;

      &:after {
        content: ' ->';
        margin-left: 6px;
        transition: transform 180ms ease;
      }

      &:hover,
      &:focus-visible {
        color: var(--lightest-slate);
        transform: translateX(2px);

        &:after {
          transform: translateX(2px);
        }
      }
    }

    .cta {
      color: var(--green);
    }
  }
`;

const Featured = () => {
  const data = useStaticQuery(graphql`
    {
      featured: allMarkdownRemark(
        filter: { fileAbsolutePath: { regex: "/content/featured/" } }
        sort: { fields: [frontmatter___date], order: ASC }
      ) {
        edges {
          node {
            frontmatter {
              title
              tech
              github
              external
              cta
              caseStudy
            }
            html
          }
        }
      }
    }
  `);

  const featuredProjects = data.featured.edges.filter(({ node }) => node);
  const revealTitle = useRef(null);
  const revealProjects = useRef([]);
  const prefersReducedMotion = usePrefersReducedMotion();

  useEffect(() => {
    if (prefersReducedMotion) {
      return;
    }

    sr.reveal(revealTitle.current, srConfig());
    revealProjects.current.forEach((ref, i) => sr.reveal(ref, srConfig(i * 100)));
  }, [prefersReducedMotion]);

  return (
    <section id="projects">
      <h2 className="numbered-heading" ref={revealTitle}>
        Some Things I’ve Built
      </h2>

      <StyledProjectsGrid>
        {featuredProjects &&
          featuredProjects.map(({ node }, i) => {
            const { frontmatter, html } = node;
            const { external, title, tech, github, cta, caseStudy } = frontmatter;
            const primaryLink = caseStudy || external || github || '#';
            const hasInternalCaseStudy = Boolean(caseStudy && caseStudy.startsWith('/'));
            const shouldShowLearnMore = Boolean(cta && cta !== external);

            return (
              <StyledProject key={i} ref={el => (revealProjects.current[i] = el)}>
                <article className="project-row">
                  <div className="project-meta">Featured</div>

                  <div className="project-body">
                    <h3 className="project-title">
                      {hasInternalCaseStudy ? (
                        <Link to={primaryLink}>{title}</Link>
                      ) : (
                        <a href={primaryLink}>{title}</a>
                      )}
                    </h3>

                    <div className="project-description" dangerouslySetInnerHTML={{ __html: html }} />

                    {tech.length && (
                      <ul className="project-tech-list">
                        {tech.map((tech, index) => (
                          <li key={index}>{tech}</li>
                        ))}
                      </ul>
                    )}

                    <div className="project-links">
                      {hasInternalCaseStudy && (
                        <Link to={primaryLink} className="cta" aria-label="Case Study Link">
                          View Case Study
                        </Link>
                      )}
                      {shouldShowLearnMore && (
                        <a href={cta} aria-label="Course Link" className="cta">
                          Learn More
                        </a>
                      )}
                      {external && (
                        <a href={external} aria-label="Open project">
                          Open Project
                        </a>
                      )}
                      {github && (
                        <a href={github} aria-label="Open repository">
                          View Repository
                        </a>
                      )}
                    </div>
                  </div>
                </article>
              </StyledProject>
            );
          })}
      </StyledProjectsGrid>
    </section>
  );
};

export default Featured;
