import React, { useEffect, useRef } from 'react';
import PropTypes from 'prop-types';
import styled, { ThemeProvider } from 'styled-components';
import { Head, Nav, Social, Email, Footer, BackToTop } from '@components';
import { GlobalStyle, theme } from '@styles';

const StyledContent = styled.div`
  position: relative;
  display: flex;
  flex-direction: column;
  min-height: 100vh;
  isolation: isolate;
  background: ${props =>
    props.$darkEditorial
      ? 'linear-gradient(180deg, #fff8ef 0%, #fff3e3 46%, #f6eadb 100%)'
      : 'transparent'};
  ${props =>
    props.$darkEditorial &&
    `
      --navy: #fff8ef;
      --dark-navy: #f4eadc;
      --light-navy: #ffffff;
      --surface-secondary: rgba(255, 255, 255, 0.72);
      --lightest-navy: rgba(122, 83, 53, 0.16);
      --navy-shadow: rgba(88, 54, 28, 0.16);
      --dark-slate: #34281f;
      --slate: #5f5045;
      --light-slate: #8a7768;
      --lightest-slate: #17120e;
      --white: #17120e;
      --green: #e85d04;
      --green-tint: rgba(232, 93, 4, 0.12);
      --blue: #0f766e;
      --violet: #9a3412;
      --cyan: #f59e0b;
    `}
`;

const StyledSpotlight = styled.div`
  position: fixed;
  inset: 0;
  pointer-events: none;
  z-index: 0;
  background: radial-gradient(
    620px circle at var(--spotlight-x, 50vw) var(--spotlight-y, 28vh),
    rgba(251, 146, 60, 0.24),
    rgba(245, 158, 11, 0.12) 34%,
    rgba(15, 118, 110, 0.055) 54%,
    transparent 72%
  );
  opacity: 0.95;
`;

const StyledPageContent = styled.div`
  position: relative;
  z-index: 1;
  flex: 1 0 auto;
`;

const Layout = ({ children, location }) => {
  const isHome = location.pathname === '/';
  const isDarkEditorial =
    isHome ||
    location.pathname.startsWith('/blog') ||
    location.pathname.startsWith('/work') ||
    location.pathname.startsWith('/archive');
  const contentRef = useRef(null);

  // Sets target="_blank" rel="noopener noreferrer" on external links
  const handleExternalLinks = () => {
    const allLinks = Array.from(document.querySelectorAll('a'));
    if (allLinks.length > 0) {
      allLinks.forEach(link => {
        if (link.host !== window.location.host) {
          link.setAttribute('rel', 'noopener noreferrer');
          link.setAttribute('target', '_blank');
        }
      });
    }
  };

  useEffect(() => {
    if (location.hash) {
      const id = location.hash.substring(1); // location.hash without the '#'
      setTimeout(() => {
        const el = document.getElementById(id);
        if (el) {
          el.scrollIntoView();
          el.focus();
        }
      }, 0);
    }

    handleExternalLinks();
  }, [location.hash]);

  useEffect(() => {
    if (typeof window === 'undefined' || !contentRef.current || !isDarkEditorial) {
      return undefined;
    }

    const content = contentRef.current;
    const prefersReducedMotion = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
    const prefersFinePointer = window.matchMedia('(pointer: fine)').matches;

    if (prefersReducedMotion || !prefersFinePointer) {
      content.style.setProperty('--spotlight-x', '50vw');
      content.style.setProperty('--spotlight-y', '24vh');
      return undefined;
    }

    let animationFrame = null;

    const moveSpotlight = event => {
      if (animationFrame) {
        window.cancelAnimationFrame(animationFrame);
      }

      animationFrame = window.requestAnimationFrame(() => {
        content.style.setProperty('--spotlight-x', `${event.clientX}px`);
        content.style.setProperty('--spotlight-y', `${event.clientY}px`);
      });
    };

    window.addEventListener('pointermove', moveSpotlight, { passive: true });

    return () => {
      window.removeEventListener('pointermove', moveSpotlight);
      if (animationFrame) {
        window.cancelAnimationFrame(animationFrame);
      }
    };
  }, [isDarkEditorial]);

  return (
    <>
      <Head />

      <div id="root">
        <ThemeProvider theme={theme}>
          <GlobalStyle />

          <a className="skip-to-content" href="#content">
            Skip to Content
          </a>

          <StyledContent ref={contentRef} $darkEditorial={isDarkEditorial}>
            {isDarkEditorial && <StyledSpotlight aria-hidden="true" />}

            <Nav isHome={isHome} location={location} isDarkEditorial={isDarkEditorial} />
            {!isHome && !isDarkEditorial && <Social isHome={isHome} />}
            {!isHome && !isDarkEditorial && <Email isHome={isHome} />}

            <StyledPageContent id="content" tabIndex="-1">
              {children}
              {!isHome && !isDarkEditorial && <Footer />}
            </StyledPageContent>

            {!isHome && !isDarkEditorial && <BackToTop />}
          </StyledContent>
        </ThemeProvider>
      </div>
    </>
  );
};

Layout.propTypes = {
  children: PropTypes.node.isRequired,
  location: PropTypes.object.isRequired,
};

export default Layout;
