import React, { useEffect, useRef } from 'react';
import styled from 'styled-components';
import { srConfig } from '@config';
import sr from '@utils/sr';
import { usePrefersReducedMotion } from '@hooks';

const StyledAboutSection = styled.section`
  max-width: 100%;

  .inner {
    display: grid;
    grid-template-columns: minmax(0, 1fr);
    gap: 34px;
  }
`;

const StyledText = styled.div`
  p {
    font-size: var(--fz-md);
    line-height: 1.8;
    max-width: 72ch;
  }

  ul.skills-list {
    display: grid;
    grid-template-columns: repeat(2, minmax(240px, 1fr));
    grid-gap: 10px 24px;
    max-width: 620px;
    padding: 0;
    margin: 20px 0 0 0;
    overflow: hidden;
    list-style: none;

    li {
      position: relative;
      padding-left: 20px;
      font-family: var(--font-mono);
      font-size: var(--fz-xs);
      line-height: 1.55;
      white-space: nowrap;

      &:before {
        content: '▹';
        position: absolute;
        left: 0;
        color: var(--green);
        font-size: var(--fz-sm);
        line-height: 12px;
      }
    }

    @media (max-width: 640px) {
      grid-template-columns: 1fr;

      li {
        white-space: normal;
      }
    }
  }

  .about-callout {
    margin-top: 16px;
    max-width: 72ch;
    color: var(--dark-slate);
  }
`;

const About = () => {
  const revealContainer = useRef(null);
  const prefersReducedMotion = usePrefersReducedMotion();

  useEffect(() => {
    if (prefersReducedMotion) {
      return;
    }

    sr.reveal(revealContainer.current, srConfig());
  }, []);

  const skills = [
    'Collaborative mindset',
    'Low-ego communication',
    'Self-starter execution',
    'Strategic thinking',
    'User-first decision making',
    'Cross-functional leadership',
  ];

  return (
    <StyledAboutSection id="about" ref={revealContainer}>
      <h2 className="numbered-heading">About Me</h2>

      <div className="inner">
        <StyledText>
          <p>
            Hello, I’m Thomas. I’ve worked across startups, contract engagements, and product teams where the
            expectation was always the same: move quickly, keep the quality high, and own the details.
          </p>

          <p>
            I’ve had the privilege of contributing to teams at{' '}
            <a href="https://crossfill.com/">Crossfill</a>,{' '}
            <a href="https://therify.co/">Therify</a>, and <a href="https://atlys.com/">Atlys</a>.
          </p>

          <p>A few strengths I bring to product teams:</p>

          <p>
            I’m at my best when a product needs more than implementation. I like shaping a clearer structure,
            tightening the interaction details, and making the UI feel coherent from the first screen all the way
            through the smallest empty state or loading state.
          </p>

          <p className="about-callout">
            I enjoy turning ambiguous product goals into clear interfaces, shaping systems that stay maintainable
            as they grow, and collaborating closely with design and product to keep momentum high without losing
            quality.
          </p>

          <ul className="skills-list">
            {skills && skills.map((skill, i) => <li key={i}>{skill}</li>)}
          </ul>
        </StyledText>
      </div>
    </StyledAboutSection>
  );
};

export default About;
